module RefModule(clk, rst, out);input clk;
   input rst;
   output [3:0] out;
   reg [3:0] obf_counter;
   assign out =  obf_counter;

   always @(posedge clk) begin
      if (rst) begin
         obf_counter <= 0;
      end else begin
         obf_counter <= obf_counter +1;
      end
   end
endmodule
